const { Manifold, CrossSection } = api;

// Spiral Fidget Cone — a smooth tapered cone whose rim ribs become deep
// helical ridges that wind from the rounded base up to a fine tip.
const p = api.params({
  height:    { type: 'number', default: 46, min: 24, max: 80, step: 1, unit: 'mm', label: 'Height' },
  baseRadius:{ type: 'number', default: 13, min: 6,  max: 24, step: 0.5, unit: 'mm', label: 'Base radius' },
  ribCount:  { type: 'int',    default: 6,  min: 3,  max: 12, label: 'Spiral ribs' },
  twistDeg:  { type: 'number', default: 720, min: 180, max: 1440, step: 30, unit: '°', label: 'Total twist' },
});

const R = p.baseRadius;
const ribs = p.ribCount;

// --- Scalloped cross-section: a core circle with rib lobes around the rim. ---
// Each lobe is a small circle straddling the rim (centre at the rim radius),
// so it bulges outward to form a rounded ridge and notches the gaps between.
const ribR = (R * Math.PI) / ribs * 0.62;   // lobe size scales with circumference / count
let cs = CrossSection.circle(R * 0.82);     // slightly inset core so lobes read as ribs
for (let i = 0; i < ribs; i++) {
  const a = (i / ribs) * Math.PI * 2;
  const cx = Math.cos(a) * R;
  const cy = Math.sin(a) * R;
  cs = cs.add(CrossSection.circle(ribR).translate([cx, cy]));
}

// --- Extrude tall, twist hard, taper to a fine tip. High nDiv => smooth helix. ---
// scaleTop is a tiny flat (not a true zero point) so the tip survives slicing
// and the booleans stay clean.
const cone = Manifold.extrude(cs, p.height, 160, p.twistDeg, 0.06);

// --- Rounded base: an oblate spheroid overlapping the bottom so the foot is
// soft and pleasant to roll, not a sharp extruded edge. ---
const baseBlend = Manifold.sphere(R * 1.04)
  .scale([1, 1, 0.5])
  .translate([0, 0, R * 0.22]);

const body = api.label(cone.add(baseBlend), 'cone', { color: '#d63aff' });

return body;

